SELECT q.* FROM qr_codes q
LEFT JOIN order_items oi ON q.order_item_id = oi.id


        AND oi.order_id = #{orderId}


        AND q.order_item_id = #{orderItemId}


        AND q.product_id = #{productId}


        AND q.status = #{status}


ORDER BY q.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(DISTINCT q.id) FROM qr_codes q
LEFT JOIN order_items oi ON q.order_item_id = oi.id


        AND oi.order_id = #{orderId}


        AND q.order_item_id = #{orderItemId}


        AND q.product_id = #{productId}


        AND q.status = #{status}
